// Helper class for Disjoint Set Union with Parity tracking
class DSU {
    private int[] parent;
    // parity[i] stores the parity of the path weight from node i to parent[i]
    private int[] parity; 
    private int n;

    public DSU(int size) {
        n = size;
        parent = new int[n];
        parity = new int[n];
        for (int i = 0; i < n; i++) {
            parent[i] = i;
            parity[i] = 0;
        }
    }

    // Finds the root of i and updates parity[i] to be the parity of the path from i to the root.
    // Returns {root, distance_parity_to_root}
    public int[] find(int i) {
        if (parent[i] == i) {
            return new int[]{i, 0};
        }

        int[] result = find(parent[i]);
        int root = result[0];
        int dist_parent_to_root = result[1];

        // Path compression
        parent[i] = root;

        // Update parity: new_parity(i -> root) = old_parity(i -> parent[i]) XOR new_parity(parent[i] -> root)
        parity[i] = parity[i] ^ dist_parent_to_root;

        return new int[]{root, parity[i]};
    }

    // Attempts to union u and v with edge weight w (0 or 1).
    // Returns true if the edge is added successfully (i.e., it maintains the even cycle property).
    public boolean union(int u, int v, int w) {
        int[] res_u = find(u);
        int root_u = res_u[0];
        int d_u = res_u[1]; // Parity of path u -> root_u

        int[] res_v = find(v);
        int root_v = res_v[0];
        int d_v = res_v[1]; // Parity of path v -> root_v

        if (root_u != root_v) {
            // They are in different components, merge them.

            // Merge root_v into root_u (arbitrarily chosen)
            parent[root_v] = root_u;

            // We need to set parity[root_v] = P(root_v -> root_u)
            // We know P(u -> v) = w
            // P(u -> v) = P(u -> root_u) XOR P(root_u -> root_v) XOR P(root_v -> v)
            // w = d_u XOR P(root_u -> root_v) XOR d_v
            // P(root_u -> root_v) = w XOR d_u XOR d_v
            // Since P(root_v -> root_u) = P(root_u -> root_v)
            parity[root_v] = w ^ d_u ^ d_v;

            return true;
        } else {
            // They are already in the same component, a cycle is formed.
            // Path parity u -> v via root: d_u XOR d_v
            // Cycle parity: (d_u XOR d_v) XOR w

            // We add the edge only if the cycle parity is 0 (even).
            return ((d_u ^ d_v) ^ w) == 0;
        }
    }
}


