// Helper structure for DSU with path parity tracking
struct DSU {
    vector<int64_t> parent;
    // diff[i] stores the parity of the path weight from i to parent[i]
    vector<int64_t> diff;
    int N;

    DSU(int64_t n) : N(n) {
        parent.resize(n);
        diff.resize(n, 0);
        for (int64_t i = 0; i < n; ++i) {
            parent[i] = i;
        }
    }

    // Finds the root of i and performs path compression, updating diff along the path
    // Returns the root R, and updates diff[i] to store parity(i -> R)
    int64_t find(int64_t i) {
        if (parent[i] == i) {
            return i;
        }
        int64_t root = find(parent[i]);

        // Update diff[i]: New diff is (old diff[i] -> parent[i]) XOR (diff[parent[i]] -> root)
        diff[i] = diff[i] ^ diff[parent[i]];

        parent[i] = root;
        return root;
    }

    // Attempts to unite u and v with edge weight w.
    // Returns true if the edge was successfully added (consistent/no new cycle or even cycle).
    bool unite(int64_t u, int64_t v, int64_t w) {
        int64_t root_u = find(u);
        int64_t root_v = find(v);

        // D_u: parity(u -> root_u), D_v: parity(v -> root_v)
        int64_t D_u = diff[u];
        int64_t D_v = diff[v];

        if (root_u != root_v) {
            // Case 1: Different components. Merge them.
            // We merge root_u into root_v.
            parent[root_u] = root_v;

            // We need: parity(u -> v) = w
            // We have: 
            // d(u) = d(root_u) ^ D_u
            // d(v) = d(root_v) ^ D_v
            // We want to set diff[root_u] = parity(root_u -> root_v)
            // d(root_u) ^ d(root_v) = w ^ D_u ^ D_v
            diff[root_u] = w ^ D_u ^ D_v;
            return true;
        } else {
            // Case 2: Same component. Check cycle condition.
            // Existing path parity (u -> v) is D_u ^ D_v.
            // New cycle parity is (D_u ^ D_v) ^ w.
            // Must be 0 for consistency.
            if ((D_u ^ D_v) == w) {
                return true;
            } else {
                // Odd cycle formed
                return false;
            }
        }
    }
};


long long solve(long long n, vector<vector<long long>>& edges) {
    if (n == 0) return 0;

    DSU dsu(n);
    long long added_edges_count = 0;

    for (const auto& edge : edges) {
        long long u = edge[0];
        long long v = edge[1];
        long long w = edge[2];

        if (dsu.unite(u, v, w)) {
